async def add_football_on_patch():
    objs = await get_all_objects()
    patch = next((o for o in objs['objects'] if 'patch' in o['name'].lower()), None)
    if not patch:
        return {'success': False, 'error': 'Patch not found'}
    x, y, z = patch['position']
    return await add_object(name='football', x=x, y=y, z=z + 0.08, shape='sphere', color='white', size=0.06)
